class Solution:
    def getTargetCopy(self, original, cloned, target):
        queue_o = [original]
        queue_c = [cloned]
        while queue_o:
            o = queue_o.pop(0)
            c = queue_c.pop(0)
            if o is None:
                continue
            if o is target:
                return c
            queue_o.append(o.left)
            queue_o.append(o.right)
            queue_c.append(c.left)
            queue_c.append(c.right)
        return None

