class Solution:
    def getTargetCopy(self, original, cloned, target):
        if original is None:
            return None
        if original is target:
            return cloned
        return (
            self.getTargetCopy(original.left, cloned.left, target)
            or self.getTargetCopy(original.right, cloned.right, target)
        )

